INSERT INTO examples (name, category, framework, files, dependencies, metadata) VALUES ('"Carousel"', '"stateful"', '"react"', '{"component/Carousel.jsx": "import React, { useState, useEffect, cloneElement } from \"react\";\r\n\r\nconst Carousel = ({ carouselItems, ...rest }) => {\r\n  const [active, setActive] = useState(0);\r\n  let scrollInterval = null;\r\n\r\n  useEffect(() => {\r\n    scrollInterval = setTimeout(() => {\r\n      setActive((active + 1) % carouselItems.length);\r\n    }, 2000);\r\n    return () => clearTimeout(scrollInterval);\r\n  });\r\n\r\n  return (\r\n    <div className=\"carousel\">\r\n      {carouselItems.map((item, index) => {\r\n        const activeClass = active === index ? \" visible\" : \"\";\r\n        return cloneElement(item, {\r\n          ...rest,\r\n          className: `carousel-item${activeClass}`\r\n        });\r\n      })}\r\n    </div>\r\n  );\r\n};\r\n\r\nexport default Carousel;\r\n", "package.json": "{\n  \"name\": \"stackblitz-starters-rzbtlt\",\n  \"version\": \"0.0.0\",\n  \"private\": true,\n  \"dependencies\": {\n    \"react\": \"18.2.0\",\n    \"react-dom\": \"18.2.0\"\n  },\n  \"scripts\": {\n    \"start\": \"react-scripts start\",\n    \"build\": \"react-scripts build\",\n    \"test\": \"react-scripts test --env=jsdom\",\n    \"eject\": \"react-scripts eject\"\n  },\n  \"devDependencies\": {\n    \"react-scripts\": \"latest\"\n  }\n}", "public/index.html": "<div id=\"app\"></div>", "src/App.js": "import React from ''react'';\nimport Carousel from \"../component/Carousel\";\nimport \"./style.css\";\n\nexport default function App() {\n  return (\n    <div className=\"App\">\n      <h1>Carousel</h1>\n      <Carousel\n        carouselItems={[\n          <div>carousel item 1</div>,\n          <div>carousel item 2</div>,\n          <div>carousel item 3</div>\n        ]}\n      />\n    </div>\n  );\n}\n", "src/style.css": "* {\n  box-sizing: border-box;\n}\n\nbody {\n  margin: 0;\n  padding: 1rem;\n  font-family: system-ui, sans-serif;\n  color: black;\n  background-color: white;\n}\n\nh1 {\n  font-weight: 800;\n  font-size: 1.5rem;\n}\n"}', '{"react": "18.2.0", "react-dom": "18.2.0"}', '{"original_path": "component/react/stateful/Carousel"}'), ('"Collapse"', '"stateful"', '"react"', '{"component/Collapse.jsx": "import React, { useState } from \"react\";\r\nconst Collapse = ({ collapsed, children }) => {\r\n  const [isCollapsed, setIsCollapsed] = useState(collapsed);\r\n\r\n  return (\r\n    <>\r\n      <button\r\n        className=\"collapse-button\"\r\n        onClick={() => setIsCollapsed(!isCollapsed)}\r\n      >\r\n        {isCollapsed ? \"Show\" : \"Hide\"} content\r\n      </button>\r\n      <div\r\n        className={`collapse-content ${isCollapsed ? \"collapsed\" : \"expanded\"}`}\r\n        aria-expanded={isCollapsed}\r\n      >\r\n        {children}\r\n      </div>\r\n    </>\r\n  );\r\n};\r\n\r\nexport default Collapse;\r\n", "package.json": "{\n  \"name\": \"stackblitz-starters-rzbtlt\",\n  \"version\": \"0.0.0\",\n  \"private\": true,\n  \"dependencies\": {\n    \"react\": \"18.2.0\",\n    \"react-dom\": \"18.2.0\"\n  },\n  \"scripts\": {\n    \"start\": \"react-scripts start\",\n    \"build\": \"react-scripts build\",\n    \"test\": \"react-scripts test --env=jsdom\",\n    \"eject\": \"react-scripts eject\"\n  },\n  \"devDependencies\": {\n    \"react-scripts\": \"latest\"\n  }\n}", "public/index.html": "<div id=\"app\"></div>", "src/style.css": "* {\n  box-sizing: border-box;\n}\n\nbody {\n  margin: 0;\n  padding: 1rem;\n  font-family: system-ui, sans-serif;\n  color: black;\n  background-color: white;\n}\n\nh1 {\n  font-weight: 800;\n  font-size: 1.5rem;\n}\n"}', '{"react": "18.2.0", "react-dom": "18.2.0"}', '{"original_path": "component/react/stateful/Collapse"}'), ('"ControlledInput"', '"stateful"', '"react"', '{"component/ControlledInput.jsx": "const ControlledInput = ({ value, onValueChange, ...rest }) => {\r\n  return (\r\n    <input\r\n      value={value}\r\n      onChange={({ target: { value } }) => onValueChange(value)}\r\n      {...rest}\r\n    />\r\n  );\r\n};\r\n\r\nexport default ControlledInput;\r\n", "component/Form.jsx": "import React, { useState } from \"react\";\r\nimport ControlledInput from \"./ControlledInput\";\r\n\r\nconst Form = () => {\r\n  const [value, setValue] = useState(\"\");\r\n\r\n  return (\r\n    <ControlledInput\r\n      type=\"text\"\r\n      placeholder=\"Insert some text here...\"\r\n      value={value}\r\n      onValueChange={setValue}\r\n    />\r\n  );\r\n};\r\n\r\nexport default Form;\r\n", "package.json": "{\n  \"name\": \"stackblitz-starters-rzbtlt\",\n  \"version\": \"0.0.0\",\n  \"private\": true,\n  \"dependencies\": {\n    \"react\": \"18.2.0\",\n    \"react-dom\": \"18.2.0\"\n  },\n  \"scripts\": {\n    \"start\": \"react-scripts start\",\n    \"build\": \"react-scripts build\",\n    \"test\": \"react-scripts test --env=jsdom\",\n    \"eject\": \"react-scripts eject\"\n  },\n  \"devDependencies\": {\n    \"react-scripts\": \"latest\"\n  }\n}", "public/index.html": "<div id=\"app\"></div>", "src/App.js": "import React from ''react'';\nimport Form from \"../component/Form\";\nimport \"./style.css\";\n\nexport default function App() {\n  return (\n    <div className=\"App\">\n      <h1>Controlled input field</h1>\n      <Form />\n    </div>\n  );\n}\n", "src/style.css": "* {\n  box-sizing: border-box;\n}\n\nbody {\n  margin: 0;\n  padding: 1rem;\n  font-family: system-ui, sans-serif;\n  color: black;\n  background-color: white;\n}\n\nh1 {\n  font-weight: 800;\n  font-size: 1.5rem;\n}\n"}', '{"react": "18.2.0", "react-dom": "18.2.0"}', '{"original_path": "component/react/stateful/ControlledInput"}'), ('"FileDrop"', '"stateful"', '"react"', '{"component/FileDrop.jsx": "import React, { useState } from \"react\";\r\n\r\nconst FileDrop = ({ onDrop }) => {\r\n  const [drag, setDrag] = React.useState(false);\r\n  const [filename, setFilename] = React.useState(\"\");\r\n  let dropRef = React.createRef();\r\n  let dragCounter = 0;\r\n\r\n  const handleDrag = (e) => {\r\n    e.preventDefault();\r\n    e.stopPropagation();\r\n  };\r\n\r\n  const handleDragIn = (e) => {\r\n    e.preventDefault();\r\n    e.stopPropagation();\r\n    dragCounter++;\r\n    if (e.dataTransfer.items && e.dataTransfer.items.length > 0) setDrag(true);\r\n  };\r\n\r\n  const handleDragOut = (e) => {\r\n    e.preventDefault();\r\n    e.stopPropagation();\r\n    dragCounter--;\r\n    if (dragCounter === 0) setDrag(false);\r\n  };\r\n\r\n  const handleDrop = (e) => {\r\n    e.preventDefault();\r\n    e.stopPropagation();\r\n    setDrag(false);\r\n    if (e.dataTransfer.files && e.dataTransfer.files.length > 0) {\r\n      onDrop(e.dataTransfer.files[0]);\r\n      setFilename(e.dataTransfer.files[0].name);\r\n      e.dataTransfer.clearData();\r\n      dragCounter = 0;\r\n    }\r\n  };\r\n\r\n  React.useEffect(() => {\r\n    let div = dropRef.current;\r\n    div.addEventListener(\"dragenter\", handleDragIn);\r\n    div.addEventListener(\"dragleave\", handleDragOut);\r\n    div.addEventListener(\"dragover\", handleDrag);\r\n    div.addEventListener(\"drop\", handleDrop);\r\n    return () => {\r\n      div.removeEventListener(\"dragenter\", handleDragIn);\r\n      div.removeEventListener(\"dragleave\", handleDragOut);\r\n      div.removeEventListener(\"dragover\", handleDrag);\r\n      div.removeEventListener(\"drop\", handleDrop);\r\n    };\r\n  });\r\n\r\n  return (\r\n    <div\r\n      ref={dropRef}\r\n      className={\r\n        drag ? \"filedrop drag\" : filename ? \"filedrop ready\" : \"filedrop\"\r\n      }\r\n    >\r\n      {filename && !drag ? <div>{filename}</div> : <div>Drop a file here!</div>}\r\n    </div>\r\n  );\r\n};\r\n\r\nexport default FileDrop;\r\n", "package.json": "{\n  \"name\": \"stackblitz-starters-rzbtlt\",\n  \"version\": \"0.0.0\",\n  \"private\": true,\n  \"dependencies\": {\n    \"react\": \"18.2.0\",\n    \"react-dom\": \"18.2.0\"\n  },\n  \"scripts\": {\n    \"start\": \"react-scripts start\",\n    \"build\": \"react-scripts build\",\n    \"test\": \"react-scripts test --env=jsdom\",\n    \"eject\": \"react-scripts eject\"\n  },\n  \"devDependencies\": {\n    \"react-scripts\": \"latest\"\n  }\n}", "public/index.html": "<div id=\"app\"></div>", "src/App.js": "import React from ''react'';\nimport FileDrop from \"../component/FileDrop\";\nimport \"./style.css\";\n\nexport default function App() {\n  return (\n    <div className=\"App\">\n      <h1>File drag and drop area</h1>\n      <FileDrop onDrop={console.log} />\n    </div>\n  );\n}\n", "src/style.css": "* {\n  box-sizing: border-box;\n}\n\nbody {\n  margin: 0;\n  padding: 1rem;\n  font-family: system-ui, sans-serif;\n  color: black;\n  background-color: white;\n}\n\nh1 {\n  font-weight: 800;\n  font-size: 1.5rem;\n}\n"}', '{"react": "18.2.0", "react-dom": "18.2.0"}', '{"original_path": "component/react/stateful/FileDrop"}'), ('"LimitedTextarea"', '"stateful"', '"react"', '{"component/LimitedTextarea.jsx": "import React, { useState } from \"react\";\r\n\r\nconst LimitedTextarea = ({ rows, cols, value, limit }) => {\r\n  const [content, setContent] = React.useState(value.slice(0, limit));\r\n\r\n  const setFormattedContent = React.useCallback(\r\n    (text) => {\r\n      setContent(text.slice(0, limit));\r\n    },\r\n    [limit, setContent]\r\n  );\r\n\r\n  return (\r\n    <>\r\n      <textarea\r\n        rows={rows}\r\n        cols={cols}\r\n        onChange={(event) => setFormattedContent(event.target.value)}\r\n        value={content}\r\n      />\r\n      <p>\r\n        {content.length}/{limit}\r\n      </p>\r\n    </>\r\n  );\r\n};\r\n\r\nexport default LimitedTextarea;\r\n", "package.json": "{\n  \"name\": \"stackblitz-starters-rzbtlt\",\n  \"version\": \"0.0.0\",\n  \"private\": true,\n  \"dependencies\": {\n    \"react\": \"18.2.0\",\n    \"react-dom\": \"18.2.0\"\n  },\n  \"scripts\": {\n    \"start\": \"react-scripts start\",\n    \"build\": \"react-scripts build\",\n    \"test\": \"react-scripts test --env=jsdom\",\n    \"eject\": \"react-scripts eject\"\n  },\n  \"devDependencies\": {\n    \"react-scripts\": \"latest\"\n  }\n}", "public/index.html": "<div id=\"app\"></div>", "src/App.js": "import React from ''react'';\nimport LimitedTextarea from \"../component/LimitedTextarea\";\nimport \"./style.css\";\n\nexport default function App() {\n  return (\n    <div className=\"App\">\n      <h1>Textarea with character limit</h1>\n      <LimitedTextarea limit={32} value=\"Hello!\" />\n    </div>\n  );\n}\n", "src/style.css": "* {\n  box-sizing: border-box;\n}\n\nbody {\n  margin: 0;\n  padding: 1rem;\n  font-family: system-ui, sans-serif;\n  color: black;\n  background-color: white;\n}\n\nh1 {\n  font-weight: 800;\n  font-size: 1.5rem;\n}\n"}', '{"react": "18.2.0", "react-dom": "18.2.0"}', '{"original_path": "component/react/stateful/LimitedTextarea"}'), ('"Modal"', '"stateful"', '"react"', '{"component/Modal.jsx": "import React, { useEffect } from \"react\";\r\n\r\nconst Modal = ({ isVisible = false, title, content, footer, onClose }) => {\r\n  const keydownHandler = ({ key }) => {\r\n    switch (key) {\r\n      case \"Escape\":\r\n        onClose();\r\n        break;\r\n      default:\r\n    }\r\n  };\r\n\r\n  React.useEffect(() => {\r\n    document.addEventListener(\"keydown\", keydownHandler);\r\n    return () => document.removeEventListener(\"keydown\", keydownHandler);\r\n  });\r\n\r\n  return !isVisible ? null : (\r\n    <div className=\"modal\" onClick={onClose}>\r\n      <div className=\"modal-dialog\" onClick={(e) => e.stopPropagation()}>\r\n        <div className=\"modal-header\">\r\n          <h3 className=\"modal-title\">{title}</h3>\r\n          <span className=\"modal-close\" onClick={onClose}>\r\n            &times;\r\n          </span>\r\n        </div>\r\n        <div className=\"modal-body\">\r\n          <div className=\"modal-content\">{content}</div>\r\n        </div>\r\n        {footer && <div className=\"modal-footer\">{footer}</div>}\r\n      </div>\r\n    </div>\r\n  );\r\n};\r\n\r\nexport default Modal;\r\n", "package.json": "{\n  \"name\": \"stackblitz-starters-rzbtlt\",\n  \"version\": \"0.0.0\",\n  \"private\": true,\n  \"dependencies\": {\n    \"react\": \"18.2.0\",\n    \"react-dom\": \"18.2.0\"\n  },\n  \"scripts\": {\n    \"start\": \"react-scripts start\",\n    \"build\": \"react-scripts build\",\n    \"test\": \"react-scripts test --env=jsdom\",\n    \"eject\": \"react-scripts eject\"\n  },\n  \"devDependencies\": {\n    \"react-scripts\": \"latest\"\n  }\n}", "public/index.html": "<div id=\"app\"></div>", "src/App.js": "import React from ''react'';\nimport React, { useState } from \"react\";\nimport Modal from \"../component/Modal\";\nimport \"./style.css\";\n\nexport default function App() {\n  const [isModal, setModal] = React.useState(false);\n  return (\n    <div className=\"App\">\n      <h1>Modal dialog</h1>\n      <button onClick={() => setModal(true)}>Click Here</button>\n      <Modal\n        isVisible={isModal}\n        title=\"Modal Title\"\n        content={<p>Add your content here</p>}\n        footer={<button>Cancel</button>}\n        onClose={() => setModal(false)}\n      />\n    </div>\n  );\n}\n", "src/style.css": "* {\n  box-sizing: border-box;\n}\n\nbody {\n  margin: 0;\n  padding: 1rem;\n  font-family: system-ui, sans-serif;\n  color: black;\n  background-color: white;\n}\n\nh1 {\n  font-weight: 800;\n  font-size: 1.5rem;\n}\n"}', '{"react": "18.2.0", "react-dom": "18.2.0"}', '{"original_path": "component/react/stateful/Modal"}'), ('"MultiselectCheckbox"', '"stateful"', '"react"', '{"component/MultiselectCheckbox.jsx": "import React, { useState } from \"react\";\r\n\r\nconst MultiselectCheckbox = ({ options, onChange }) => {\r\n  const [data, setData] = React.useState(options);\r\n\r\n  const toggle = (index) => {\r\n    const newData = [...data];\r\n    newData.splice(index, 1, {\r\n      label: data[index].label,\r\n      checked: !data[index].checked\r\n    });\r\n    setData(newData);\r\n    onChange(newData.filter((x) => x.checked));\r\n  };\r\n\r\n  return (\r\n    <>\r\n      {data.map((item, index) => (\r\n        <label key={item.label}>\r\n          <input\r\n            readOnly\r\n            type=\"checkbox\"\r\n            checked={item.checked || false}\r\n            onClick={() => toggle(index)}\r\n          />\r\n          {item.label}\r\n        </label>\r\n      ))}\r\n    </>\r\n  );\r\n};\r\n\r\nexport default MultiselectCheckbox;\r\n", "package.json": "{\n  \"name\": \"stackblitz-starters-rzbtlt\",\n  \"version\": \"0.0.0\",\n  \"private\": true,\n  \"dependencies\": {\n    \"react\": \"18.2.0\",\n    \"react-dom\": \"18.2.0\"\n  },\n  \"scripts\": {\n    \"start\": \"react-scripts start\",\n    \"build\": \"react-scripts build\",\n    \"test\": \"react-scripts test --env=jsdom\",\n    \"eject\": \"react-scripts eject\"\n  },\n  \"devDependencies\": {\n    \"react-scripts\": \"latest\"\n  }\n}", "public/index.html": "<div id=\"app\"></div>", "src/App.js": "import React from ''react'';\nimport MultiselectCheckbox from \"../component/MultiselectCheckbox\";\nimport \"./style.css\";\n\nexport default function App() {\n  const options = [{ label: \"Item One\" }, { label: \"Item Two\" }];\n\n  return (\n    <div className=\"App\">\n      <h1>Multiple Select Checkbox</h1>\n      <MultiselectCheckbox\n        options={options}\n        onChange={(data) => {\n          console.log(data);\n        }}\n      />\n    </div>\n  );\n}\n", "src/style.css": "* {\n  box-sizing: border-box;\n}\n\nbody {\n  margin: 0;\n  padding: 1rem;\n  font-family: system-ui, sans-serif;\n  color: black;\n  background-color: white;\n}\n\nh1 {\n  font-weight: 800;\n  font-size: 1.5rem;\n}\n"}', '{"react": "18.2.0", "react-dom": "18.2.0"}', '{"original_path": "component/react/stateful/MultiselectCheckbox"}'), ('"PasswordRevealer"', '"stateful"', '"react"', '{"component/PasswordRevealer.jsx": "import React, { useState } from \"react\";\r\n\r\nconst PasswordRevealer = ({ value }) => {\r\n  const [shown, setShown] = React.useState(false);\r\n  return (\r\n    <>\r\n      <input type={shown ? \"text\" : \"password\"} value={value} />\r\n      <button onClick={() => setShown(!shown)}>Show/Hide</button>\r\n    </>\r\n  );\r\n};\r\n\r\nexport default PasswordRevealer;\r\n", "package.json": "{\n  \"name\": \"stackblitz-starters-rzbtlt\",\n  \"version\": \"0.0.0\",\n  \"private\": true,\n  \"dependencies\": {\n    \"react\": \"18.2.0\",\n    \"react-dom\": \"18.2.0\"\n  },\n  \"scripts\": {\n    \"start\": \"react-scripts start\",\n    \"build\": \"react-scripts build\",\n    \"test\": \"react-scripts test --env=jsdom\",\n    \"eject\": \"react-scripts eject\"\n  },\n  \"devDependencies\": {\n    \"react-scripts\": \"latest\"\n  }\n}", "public/index.html": "<div id=\"app\"></div>", "src/App.js": "import React from ''react'';\nimport PasswordRevealer from \"../component/PasswordRevealer\";\nimport \"./style.css\";\n\nexport default function App() {\n  return (\n    <div className=\"App\">\n      <h1>Show/hide password toggle</h1>\n      <PasswordRevealer />\n    </div>\n  );\n}\n", "src/style.css": "* {\n  box-sizing: border-box;\n}\n\nbody {\n  margin: 0;\n  padding: 1rem;\n  font-family: system-ui, sans-serif;\n  color: black;\n  background-color: white;\n}\n\nh1 {\n  font-weight: 800;\n  font-size: 1.5rem;\n}\n"}', '{"react": "18.2.0", "react-dom": "18.2.0"}', '{"original_path": "component/react/stateful/PasswordRevealer"}'), ('"RippleButton"', '"stateful"', '"react"', '{"component/RippleButton.jsx": "import React, { useState } from \"react\";\r\n\r\nconst RippleButton = ({ children, onClick }) => {\r\n  const [coords, setCoords] = React.useState({ x: -1, y: -1 });\r\n  const [isRippling, setIsRippling] = React.useState(false);\r\n\r\n  React.useEffect(() => {\r\n    if (coords.x !== -1 && coords.y !== -1) {\r\n      setIsRippling(true);\r\n      setTimeout(() => 